select *
from nx_department as dep
where dep.nx_department_driver_id = #{userId}

select *, subsd.nx_department_id 'subs_nx_department_id', subsd.nx_department_ocr_prompt_image 'subs_nx_department_ocr_prompt_image', subsd.nx_department_app_id 'subs_nx_department_app_id', subsd.nx_department_name 'subs_nx_department_name', subsd.nx_department_pick_name 'subs_nx_department_pick_name', subsd.nx_department_order_code 'subs_nx_department_order_code', subsd.nx_department_settle_type 'subs_nx_department_settle_type', subsd.nx_department_attr_name 'subs_nx_department_attr_name', subsd.nx_department_type 'subs_nx_department_type', subsd.nx_department_print_name 'subs_nx_department_print_name', subsd.nx_department_show_weeks 'subs_nx_department_show_weeks', subsd.nx_department_father_id 'subs_nx_department_father_id', subsd.nx_department_is_group_dep 'subs_nx_department_is_group_dep', subsd.nx_department_dis_id 'subs_nx_department_dis_id', subsd.nx_department_working_status 'subs_nx_department_working_status', subsd.nx_department_file_path 'subs_nx_department_file_path', subsd.nx_department_join_date 'subs_nx_department_join_date', subsd.nx_department_order_total 'subs_nx_department_order_total', subsd.nx_department_pinyin 'subs_nx_department_pinyin', subsd.nx_department_sub_amount 'subs_nx_department_sub_amount', (select count(*) from nx_ocr_task as ta where ta.nx_ocr_task_department_father_id = d.nx_department_id and ta.nx_ocr_task_status < 2) 'task_count' from nx_department as d left join nx_department as subsd on subsd.nx_department_father_id = d.nx_department_id left join nx_distributer_pay as ndp on ndp.nx_ndp_nx_new_dis_id = d.nx_department_id left join nx_department_distributer_label as dl on dl.nx_ddl_department_id = d.nx_department_id
and d.nx_department_dis_id = #{disId}
and d.nx_department_gb_distributer_id is null
and d.nx_department_settle_type = #{type}
and d.nx_department_is_group_dep = #{isGroup}
and d.nx_department_sub_amount = #{subAmount}
and dl.nx_ddl_distributer_label_id = #{labelId}
and d.nx_department_is_group_dep = 1
order by d.nx_department_pinyin

select count(*) from nx_department as d


    and d.nx_department_dis_id = #{disId}


    and d.nx_department_settle_type = #{type}


    and d.nx_department_is_group_dep = #{isGroup}


    and d.nx_department_sub_amount = #{subAmount}

select * from nx_department as d


        and d.nx_department_dis_id = #{disId}


        and d.nx_department_settle_type = #{type}


        and d.nx_department_is_group_dep = #{isGroup}


        and d.nx_department_sub_amount = #{subAmount}
